// frontend/src/components/Dashboard/Dashboard.js
import React, { useState, useEffect, useCallback } from 'react';
import {
  Box,
  Container,
  Grid,
  Paper,
  Typography,
  Button,
  AppBar,
  Toolbar,
  IconButton,
  Menu,
  MenuItem,
  Avatar,
  Divider,
  Alert,
  CircularProgress,
  Card,
  CardContent,
  Chip,
  useTheme,
  useMediaQuery
} from '@mui/material';
import {
  AccountCircle,
  Logout,
  Refresh,
  TrendingUp,
  TrendingDown,
  AccountBalanceWallet,
  ShowChart,
  History,
  Sync,
  Visibility,
  VisibilityOff,
  AdminPanelSettings
} from '@mui/icons-material';
import { useNavigate } from 'react-router-dom';
import { toast } from 'react-toastify';
import authService from '../../services/authService';
import { useAuth } from '../../contexts/AuthContext';
import dashboardService from '../../services/dashboardService';
import logger from '../../utils/logger';
import StatsCards from './StatsCards';
import PNLCard from './PNLCard';
import TradesTable from './TradesTable';
import AccountBalance from './AccountBalance';
import OpenPositions from './OpenPositions';
import Profile from './Profile';
import DateFilter from './DateFilter';
import FuturesBalanceCard from './FuturesBalanceCard';


const Dashboard = () => {
  const navigate = useNavigate();
  const theme = useTheme();
  const isMobile = useMediaQuery(theme.breakpoints.down('md'));
  const { user, logout, setUser } = useAuth();

  const [anchorEl, setAnchorEl] = useState(null);
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);
  const [error, setError] = useState('');
  const [profileOpen, setProfileOpen] = useState(false);
  const [autoSyncStatus, setAutoSyncStatus] = useState(false);
  const [autoSyncLoading, setAutoSyncLoading] = useState(false);
  const [hideValues, setHideValues] = useState(false);
  const [dateFilters, setDateFilters] = useState({});

  const [dashboardData, setDashboardData] = useState({
    stats: null,
    openTrades: [],
    closedTrades: [],
    profitData: [],
    balance: null
  });

  const loadDashboardData = useCallback(async (isSilent = false) => {
    try {
      if (!isSilent) {
        setLoading(true);
      }
      setError('');

      // Nota: Verificação de sessão removida para evitar logout automático
      // A autenticação é verificada automaticamente pelos interceptadores do axios

      // Carregar dados do dashboard em paralelo
      const [stats, openTrades, closedTrades, profitData, balance, apiStatus] = await Promise.all([
        dashboardService.getUserStats(),
        dashboardService.getOpenTrades(),
        dashboardService.getClosedTrades(dateFilters),
        dashboardService.getProfitCurveData(),
        dashboardService.getAccountBalance(),
        dashboardService.getApiStatus()
      ]);

      // Log seguro apenas do status
      logger.secure('Dashboard data loaded successfully');

      const combinedBalance = {
        ...(balance.data || balance),
        api_configured: apiStatus.configured 
      };

      // Debug: verificar dados de trades fechados
      console.log('🔍 DEBUG - Dados recebidos:');
      console.log('closedTrades response:', closedTrades);
      console.log('closedTrades.data:', closedTrades?.data);
      console.log('Is array?', Array.isArray(closedTrades?.data));

      const processedClosedTrades = Array.isArray(closedTrades?.data) ? closedTrades.data : (Array.isArray(closedTrades) ? closedTrades : []);
      console.log('processedClosedTrades:', processedClosedTrades);
      console.log('processedClosedTrades length:', processedClosedTrades.length);

      setDashboardData({
        stats: stats?.data || stats,
        openTrades: Array.isArray(openTrades?.data) ? openTrades.data : (Array.isArray(openTrades) ? openTrades : []),
        closedTrades: processedClosedTrades,
        profitData: Array.isArray(profitData?.data) ? profitData.data : (Array.isArray(profitData) ? profitData : []),
        balance: combinedBalance
      });
    } catch (error) {
      console.error('Erro ao carregar dashboard:', error);
      if (!isSilent) {
        if (error.message === 'Não autenticado' || error.message === 'Login necessário' || error.status === 401) {
          setError('Sessão expirada. Você será redirecionado para o login.');
        } else {
          setError('Erro ao carregar dados do dashboard');
        }
      }
    } finally {
      if (!isSilent) {
        setLoading(false);
      }
    }
  }, [dateFilters]);

  useEffect(() => {
    loadDashboardData(false); // Carga inicial com loading
    const interval = setInterval(() => {
      loadDashboardData(true); // Atualizações silenciosas
      checkAutoSyncStatus();
    }, 30000);
    return () => clearInterval(interval);
  }, [loadDashboardData]);

  const handleRefresh = async () => {
    setRefreshing(true);
    await loadDashboardData(false);
    setRefreshing(false);
    toast.success('Dados atualizados!');
  };

  const handleSyncTrades = async () => {
    try {
      setRefreshing(true);
      await dashboardService.syncTrades();
      await loadDashboardData(false);
      toast.success('Trades sincronizados com sucesso!');
    } catch (error) {
      console.error('Erro ao sincronizar trades:', error);
      toast.error('Erro ao sincronizar trades');
    } finally {
      setRefreshing(false);
    }
  };

  const handleSyncClosedTrades = async () => {
    try {
      setRefreshing(true);
      const result = await dashboardService.syncClosedTrades();
      await loadDashboardData(false);
      toast.success(`${result.message || 'Trades fechados sincronizados com sucesso!'}`);
    } catch (error) {
      console.error('Erro ao sincronizar trades fechados:', error);
      toast.error(error.message || 'Erro ao sincronizar trades fechados');
    } finally {
      setRefreshing(false);
    }
  };

  const checkAutoSyncStatus = async () => {
    try {
      const response = await dashboardService.getAutoSyncStatus();
      setAutoSyncStatus(response.running || false);
    } catch (error) {
      console.error('Erro ao verificar status da sincronização automática:', error);

      // Verificar se é erro de autenticação
      if (error.message === 'Login necessário' || error.status === 401) {
        // O interceptador já vai lidar com o redirecionamento
        return;
      }
    }
  };

  const handleToggleAutoSync = async () => {
    try {
      setAutoSyncLoading(true);

      if (autoSyncStatus) {
        await dashboardService.stopAutoSync();
        toast.success('Sincronização automática desativada!');
      } else {
        await dashboardService.startAutoSync();
        toast.success('Sincronização automática ativada!');
      }

      await checkAutoSyncStatus();
    } catch (error) {
      console.error('Erro ao alterar sincronização automática:', error);
      toast.error('Erro ao alterar sincronização automática');
    } finally {
      setAutoSyncLoading(false);
    }
  };

  const handleMenuOpen = (event) => {
    setAnchorEl(event.currentTarget);
  };

  const handleMenuClose = () => {
    setAnchorEl(null);
  };

  const handleProfileOpen = () => {
    setProfileOpen(true);
    handleMenuClose();
  };

  const handleProfileClose = () => {
    setProfileOpen(false);
  };

  const handleUserUpdate = (updatedUser) => {
    setUser(updatedUser); // Atualizar o usuário no contexto
  };

  const handleLogout = async () => {
    try {
      setAnchorEl(null);
      await logout();
      // O logout vai redirecionar automaticamente
    } catch (error) {
      console.error('Erro no logout:', error);
    }
  };

  const handleGoToAdmin = () => {
    navigate('/admin');
    handleMenuClose();
  };

  const handleToggleValues = () => {
    setHideValues(!hideValues);
  };

  const handleDateFilterChange = (filters) => {
    setDateFilters(filters);
  };

  if (loading) {
    return (
      <Box sx={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100vh' }}>
        <CircularProgress />
      </Box>
    );
  }

  return (
    <Box sx={{ flexGrow: 1, minHeight: '100vh', bgcolor: 'background.default' }}>
      <Box sx={{ position: 'sticky', top: 0, zIndex: 1100, backgroundColor: 'background.default' }}>
        <AppBar position="static" elevation={0} sx={{ bgcolor: 'background.paper', borderBottom: 1, borderColor: 'divider' }}>
          <Toolbar>
            <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, flexGrow: 1 }}>
              <Typography variant="h6" component="div" sx={{ fontWeight: 'bold', color: 'primary.main' }}>
                Nautilus Automação
              </Typography>
            </Box>
            <Box sx={{ position: 'absolute', left: '50%', transform: 'translateX(-50%)', display: 'flex', alignItems: 'center', gap: 1, zIndex: 1 }}>
              {user && (
                <Typography variant="h6" sx={{ color: 'text.primary', fontWeight: 'medium', whiteSpace: 'nowrap' }}>
                  Bem-vindo, {user.full_name?.trim() || user.email.split('@')[0]}!
                </Typography>
              )}
            </Box>
            <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, mr: 2 }}>
              {user?.is_admin && (
                <Button startIcon={<AdminPanelSettings />} onClick={handleGoToAdmin} size="small" variant="contained" color="secondary" sx={{ display: { xs: 'none', md: 'flex' } }}>
                  Admin
                </Button>
              )}
              <Button startIcon={<Sync />} onClick={handleToggleAutoSync} disabled={autoSyncLoading} size="small" variant={autoSyncStatus ? "contained" : "outlined"} color={autoSyncStatus ? "success" : "primary"} sx={{ display: { xs: 'none', md: 'flex' } }}>
                {autoSyncStatus ? 'Auto-Sync ON' : 'Auto-Sync OFF'}
              </Button>
              <Button startIcon={<Sync />} onClick={handleSyncTrades} disabled={refreshing} size="small" variant="outlined" sx={{ display: { xs: 'none', sm: 'flex' } }}>
                Sincronizar
              </Button>
              <Button startIcon={<Sync />} onClick={handleSyncClosedTrades} disabled={refreshing} size="small" variant="outlined" sx={{ display: { xs: 'none', sm: 'flex' } }}>
                Sincronizar Trades Fechados
              </Button>

              <IconButton onClick={handleToggleValues} color="default" title={hideValues ? "Mostrar valores" : "Ocultar valores"}>
                {hideValues ? <VisibilityOff /> : <Visibility />}
              </IconButton>
              <IconButton onClick={handleRefresh} disabled={refreshing} color="primary">
                <Refresh />
              </IconButton>
            </Box>
            <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
              <IconButton size="large" onClick={handleMenuOpen} color="inherit">
                <Avatar sx={{ width: 32, height: 32, bgcolor: 'primary.main' }}>
                  {user?.full_name?.trim()?.charAt(0) || <AccountCircle />}
                </Avatar>
              </IconButton>
            </Box>
            <Menu anchorEl={anchorEl} open={Boolean(anchorEl)} onClose={handleMenuClose} transformOrigin={{ horizontal: 'right', vertical: 'top' }} anchorOrigin={{ horizontal: 'right', vertical: 'bottom' }}>
              <MenuItem disabled><Typography variant="body2" color="text.secondary">{user?.email}</Typography></MenuItem>
              <Divider />
              {user?.is_admin && (
                <MenuItem onClick={handleGoToAdmin}>
                  <AdminPanelSettings fontSize="small" sx={{ mr: 1, color: 'secondary.main' }} />
                  <Typography sx={{ color: 'secondary.main', fontWeight: 'bold' }}>Painel Admin</Typography>
                </MenuItem>
              )}
              {user?.is_admin && <Divider />}
              <MenuItem onClick={handleProfileOpen}><AccountCircle fontSize="small" sx={{ mr: 1 }} /> Perfil</MenuItem>
              <MenuItem onClick={handleLogout}><Logout fontSize="small" sx={{ mr: 1 }} /> Sair</MenuItem>
            </Menu>
          </Toolbar>
        </AppBar>
        <Box sx={{ backgroundColor: 'background.default', borderBottom: '1px solid', borderColor: 'divider', py: 2 }}>
          <Container maxWidth="xl">
            {error && <Alert severity="error" sx={{ mb: 3 }}>{error}</Alert>}
            <StatsCards stats={dashboardData.stats} loading={refreshing} hideValues={hideValues} />
          </Container>
        </Box>
      </Box>

      <Container maxWidth="xl" sx={{ pt: 3, pb: 3 }}>
        <Grid container spacing={3}>
          <Grid item xs={12}>
            <FuturesBalanceCard balance={dashboardData.stats?.account_balance_usd} loading={loading} />
          </Grid>
          <Grid item xs={12}>
            <OpenPositions user={user} hideValues={hideValues} />
          </Grid>
          <Grid item xs={12}>
            <Paper sx={{ p: 3, mt: 3 }}>
              <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', mb: 2 }}>
                <Typography variant="h6" sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                  <History color="primary" />
                  Histórico de Trades
                </Typography>
                <DateFilter onFilterChange={handleDateFilterChange} currentFilters={dateFilters} />
              </Box>
              <TradesTable trades={dashboardData.closedTrades} loading={refreshing} hideValues={hideValues} />
            </Paper>
          </Grid>
        </Grid>
      </Container>

      <Profile open={profileOpen} onClose={handleProfileClose} user={user} onUserUpdate={handleUserUpdate} />

    </Box>
  );
};

export default Dashboard;
